  1	import {
  2	  AlertingRulesSourceExtension,
  3	  isAlertingRulesSource,
  4	  useActiveNamespace,
  5	  useResolvedExtensions,
  6	} from '@openshift-console/dynamic-plugin-sdk';
  7	import * as React from 'react';
  8	import { Redirect, Route, Switch } from 'react-router-dom';
  9	
 10	import { getAllQueryArguments } from './console/utils/router';
 11	
 12	import MonitoringDashboardsPage from './dashboards/perses/dashboard-page';
 13	import MonitoringLegacyDashboardsPage from './dashboards/legacy/legacy-dashboard-page';
 14	import { QueryBrowserPage } from './metrics';
 15	import { CreateSilence, EditSilence } from './silence-form';
 16	import { TargetsUI } from './targets';
 17	
 18	import './_monitoring.scss';
 19	import { UrlRoot, usePerspective } from './hooks/usePerspective';
 20	import AlertsPage from './alerting/AlertsPage';
 21	import AlertsDetailsPage from './alerting/AlertsDetailPage';
 22	import { useRulesAlertsPoller } from './hooks/useRulesAlertsPoller';
 23	import { useSilencesPoller } from './hooks/useSilencesPoller';
 24	import SilencesPage from './alerting/SilencesPage';
 25	import SilencesDetailsPage from './alerting/SilencesDetailPage';
 26	import AlertRulesDetailsPage from './alerting/AlertRulesDetailsPage';
 27	import AlertingPage from './alerting/AlertingPage';
 28	import { QueryParamProvider } from 'use-query-params';
 29	import { ReactRouter5Adapter } from 'use-query-params/adapters/react-router-5';
 30	
 31	export const PersesContext = React.createContext(false);
 32	
 33	const PollingPagesRouter = () => {
 34	  const { alertingContextId, perspective, urlRoot } = usePerspective();
 35	
 36	  const [namespace] = useActiveNamespace();
 37	
 38	  const [customExtensions] =
 39	    useResolvedExtensions<AlertingRulesSourceExtension>(isAlertingRulesSource);
 40	
 41	  const alertsSource = React.useMemo(
 42	    () =>
 43	      customExtensions
 44	        .filter((extension) => extension.properties.contextId === alertingContextId)
 45	        .map((extension) => extension.properties),
 46	    [customExtensions, alertingContextId],
 47	  );
 48	
 49	  useRulesAlertsPoller(namespace, alertsSource);
 50	  useSilencesPoller({ namespace });
 51	
 52	  if (perspective === 'dev') {
 53	    return <DevelopmentAlertingRouter />;
 54	  }
 55	
 56	  return <AlertingRouter root={urlRoot} />;
 57	};
 58	
 59	const AlertingRouter: React.FC<{ root: UrlRoot }> = ({ root }) => (
 60	  <Switch>
 61	    <Route
 62	      path={`/${root}/(alerts|alertrules|silences|incidents)`}
 63	      exact
 64	      component={AlertingPage}
 65	    />
 66	    <Route path={`/${root}/alertrules/:id`} exact component={AlertRulesDetailsPage} />
 67	    <Route path={`/${root}/alerts/:ruleID`} exact component={AlertsDetailsPage} />
 68	    <Route path={`/${root}/silences/:id`} exact component={SilencesDetailsPage} />
 69	    <Route path={`/${root}/silences/:id/edit`} exact component={EditSilence} />
 70	  </Switch>
 71	);
 72	
 73	const DevelopmentAlertingRouter = () => (
 74	  <Switch>
 75	    <Route path="/dev-monitoring/ns/:ns/alerts" exact component={AlertsPage} />
 76	    <Route path="/dev-monitoring/ns/:ns/alerts/:ruleID" component={AlertsDetailsPage} />
 77	    <Route path="/dev-monitoring/ns/:ns/rules/:id" exact component={AlertRulesDetailsPage} />
 78	    <Route path="/dev-monitoring/ns/:ns/silences" exact component={SilencesPage} />
 79	    <Route path="/dev-monitoring/ns/:ns/silences/:id" exact component={SilencesDetailsPage} />
 80	    <Route path="/dev-monitoring/ns/:ns/silences/:id/edit" exact component={EditSilence} />
 81	  </Switch>
 82	);
 83	
 84	const NonPollingRouter: React.FC<{ root: UrlRoot }> = ({ root }) => (
 85	  <Switch>
 86	    {/* This redirect also handles the `/${root}/#/alerts?...` link URLs generated by
 87	    Alertmanager (because the `#` is considered the end of the URL) */}
 88	    <Redirect from={`/${root}`} exact to={`/${root}/alerts`} />
 89	    <Route path={`/${root}/silences/~new`} exact component={CreateSilence} />
 90	
 91	    <Route path={`/${root}/v2/dashboards`} exact component={MonitoringDashboardsPage} />
 92	    <Route
 93	      path={`/${root}/dashboards/:dashboardName?`}
 94	      exact
 95	      component={MonitoringLegacyDashboardsPage}
 96	    />
 97	
 98	    <Route path={`/${root}/graph`} exact component={PrometheusRouterRedirect} />
 99	    <Route path={`/${root}/query-browser`} exact component={QueryBrowserPage} />
100	
101	    <Route path={`/${root}/targets`} component={TargetsUI} />
102	
103	    <Route component={PollingPagesRouter} />
104	  </Switch>
105	);
106	
107	const DevelopmentRouter = () => (
108	  <Switch>
109	    <Route path="/dev-monitoring/ns/:ns/" exact component={MonitoringLegacyDashboardsPage} />
110	    <Route path="/dev-monitoring/ns/:ns/silences/~new" exact component={CreateSilence} />
111	    <Route path="/dev-monitoring/ns/:ns/metrics" exact component={QueryBrowserPage} />
112	
113	    <Route component={PollingPagesRouter} />
114	  </Switch>
115	);
116	
117	const AcmRouter = () => (
118	  <Switch>
119	    {/* This redirect also handles the `/multicloud/monitoring/#/alerts?...` link URLs generated by
120	  Alertmanager (because the `#` is considered the end of the URL) */}
121	    <Redirect from="/multicloud/monitoring" exact to="/monitoring/alerts" />
122	    <Route path="/multicloud/monitoring/silences/~new" exact component={CreateSilence} />
123	
124	    <Route path="/multicloud/monitoring/v2/dashboards" exact component={MonitoringDashboardsPage} />
125	
126	    <Route component={PollingPagesRouter} />
127	  </Switch>
128	);
129	
130	const MonitoringRouter = () => {
131	  const { perspective, urlRoot } = usePerspective();
132	
133	  return (
134	    <QueryParamProvider adapter={ReactRouter5Adapter}>
135	      {(() => {
136	        switch (perspective) {
137	          case 'admin':
138	          case 'virtualization-perspective':
139	            return <NonPollingRouter root={urlRoot} />;
140	          case 'dev':
141	            return <DevelopmentRouter />;
142	          case 'acm':
143	            return <AcmRouter />;
144	        }
145	      })()}
146	    </QueryParamProvider>
147	  );
148	};
149	
150	// Handles links that have the Prometheus UI's URL format (expected for links in alerts sent by
151	// Alertmanager). The Prometheus UI specifies the PromQL query with the GET param `g0.expr`, so we
152	// use that if it exists. Otherwise, just go to the query browser page with no query.
153	const PrometheusRouterRedirect = () => {
154	  const params = getAllQueryArguments();
155	  // leaving perspective redirect to future work
156	  return <Redirect to={`/monitoring/query-browser?query0=${params['g0.expr'] || ''}`} />;
157	};
158	
159	export default MonitoringRouter;

